        'purchase_success' => '¡Oficial activado con éxito!',
        'purchase_error' => 'Se ha producido un error. Por favor, inténtalo de nuevo.',
        'officer_commander_title' => 'Comandante',
        'officer_commander_description' => 'El rango de Comandante ha demostrado su necesidad incontables veces en la guerra moderna. Gracias a la estructura de mando simplificada, las instrucciones se pueden procesar más rápidamente. ¡Con él mantendrás una visión general de tu imperio! Así desarrollarás estructuras que te permitirán ir siempre un paso por delante de tu enemigo.',
        'officer_commander_benefits' => 'Con el Comandante tendrás una vista general de todo el imperio, un espacio de misión adicional y la posibilidad de establecer el orden de los recursos saqueados.',
        'officer_commander_benefit_favourites' => '+40 favoritos',
        'officer_commander_benefit_queue' => 'Lista de construcción',
        'officer_commander_benefit_scanner' => 'Escáner de transportes',
        'officer_commander_benefit_ads' => 'Sin publicidad',
        'officer_commander_tooltip' => '<b>+40 favoritos</b><p>Con más favoritos podrás guardar y compartir más mensajes.</p><br/><b>Lista de construcción</b><p>Añade hasta 4 encargos de construcción o de investigación adicionales a la vez a la lista.</p><br/><b>Escáner de transportes</b><p>Muestra la cantidad de recursos que las Naves de carga llevan a tus planetas.</p><br/><b>Sin publicidad</b><p>No ves más publicidad de otros juegos, sino únicamente información sobre eventos y promociones relacionadas con OGame.</p>',
        'officer_admiral_title' => 'Almirante',
        'officer_admiral_description' => 'El Almirante de flota es un veterano de guerra experimentado y un habilidoso estratega. En las batallas más duras, es capaz de visualizar la situación y mantener una comunicación fluida con sus almirantes subordinados. Un emperador sabio puede confiar en su ayuda durante los combates y guiar más flotas al campo de batalla de forma simultánea. Además, el Almirante desbloquea un espacio de expedición adicional e indica a las tropas en qué orden han de cargar los distintos tipos de recursos tras el ataque. Además, ofrece veinte espacios de guardado adicionales para las simulaciones de combate.',
        'officer_admiral_benefits' => '+1 espacio de expedición, posibilidad de establecer prioridades de recursos tras un ataque, +20 espacios de guardado en el simulador de combate.',
        'officer_admiral_benefit_fleet_slots' => 'Cantidad máxima de flotas +2',
        'officer_admiral_benefit_expeditions' => 'Número máximo de expediciones +1',
        'officer_admiral_benefit_escape' => 'Tasa de retirada de flotas mejorada',
        'officer_admiral_benefit_save_slots' => 'Máx. espacios de guardado +20',
        'officer_admiral_tooltip' => '<b>Cantidad máxima de flotas +2</b><p>Puedes enviar más flotas al mismo tiempo.</p><br/><b>Número máximo de expediciones +1</b><p>Recibes un espacio de expedición adicional.</p><br/><b>Tasa de retirada de flotas mejorada</b><p>Hasta que alcances 500.000 puntos, tus flotas pueden retirarse cuando las fuerzas enemigas triplican las tuyas.</p><br/><b>Máx. espacios de guardado +20</b><p>Puedes guardar más simulaciones de combate a la vez.</p>',
        'officer_engineer_title' => 'Ingeniero',
        'officer_engineer_description' => 'El Ingeniero es un especialista en gestión de energía. En tiempos de paz aumenta la energía de todas las colonias. En caso de ataque, garantiza el abastecimiento de energía a las defensas planetarias y evita posibles sobrecargas, lo que reduce la cantidad de defensas perdidas en combate.',
        'officer_engineer_benefits' => '+10% de energía producida en todos los planetas, el 50% de las defensas destruidas sobreviven al combate.',
        'officer_engineer_benefit_defence' => 'Pérdida de instalaciones de defensa reducida a la mitad',
        'officer_engineer_benefit_energy' => '+10 % de producción de energía',
        'officer_engineer_tooltip' => '<b>Pérdida de instalaciones de defensa reducida a la mitad</b><p>Tras una batalla, se restaura la mitad de las instalaciones de defensa.</p><br/><b>+10 % de producción de energía</b><p>Tus Plantas de energía y tus Satélites solares generan un 10 % más de energía.</p>',
        'officer_geologist_title' => 'Geólogo',
        'officer_geologist_description' => 'El Geólogo es un experto en astrominerología y astrocristalografía. Asistido por su equipo de ingenieros metalúrgicos y químicos, ayuda a gobiernos interplanetarios a explotar fuentes de recursos y a optimizar su refinamiento.',
        'officer_geologist_benefits' => '+10% de producción de metal, cristal y deuterio en todos los planetas.',
        'officer_geologist_benefit_mines' => '+10 % de producción de mineral',
        'officer_geologist_tooltip' => '<b>+10 % de producción de mineral</b><p>Tus Minas producen un 10 % más.</p>',
        'officer_technocrat_title' => 'Tecnócrata',
        'officer_technocrat_description' => 'El gremio de los Tecnócratas está compuesto de auténticos genios; se los puede encontrar dondequiera que se exploren los límites de la capacidad humana. El Tecnócrata utiliza un código que ningún ser humano normal puede descifrar; su mera presencia inspira a los investigadores del imperio.',
        'officer_technocrat_benefits' => '-25% de tiempo de investigación en todas las tecnologías.',
        'officer_technocrat_benefit_espionage' => '+2 al nivel de espionaje',
        'officer_technocrat_benefit_research' => 'Un 25 % menos de tiempo de investigación',
        'officer_technocrat_tooltip' => '<b>+2 al nivel de espionaje</b><p>Se añaden 2 niveles de espionaje.</p><br/><b>Un 25 % menos de tiempo de investigación</b><p>Tus investigaciones requieren un 25 % menos de tiempo para finalizar.</p>',
        'officer_all_officers_title' => 'Grupo de comando',
        'officer_all_officers_description' => 'Con este lote te harás no solo con un especialista, sino con toda una tripulación. Recibes todos los efectos de los oficiales individuales, además de ventajas adicionales que solo se pueden conseguir con el paquete completo.\nMientras el experimentado Comandante dirige estratégicamente el proceso, los oficiales se encargan de la gestión de la energía, el abastecimiento de sistemas, la explotación de recursos y el refinado. Además impulsan la investigación y aportan su experiencia de batalla a los enfrentamientos espaciales.',
        'officer_all_officers_benefits' => 'Todos los beneficios del Comandante, Almirante, Ingeniero, Geólogo y Tecnócrata, además de bonificaciones exclusivas disponibles solo con el paquete completo.',
        'officer_all_officers_benefit_fleet_slots' => 'Cantidad de flotas máx. +1',
        'officer_all_officers_benefit_energy' => '+2 % de producción de energía',
        'officer_all_officers_benefit_mines' => '+2 % de producción de mineral',
        'officer_all_officers_benefit_espionage' => '+1 al nivel de espionaje',
        'officer_all_officers_tooltip' => '<b>Cantidad de flotas máx. +1</b><p>Puedes enviar varias flotas a la vez.</p><br/><b>+2 % de producción de energía</b><p>Tus Plantas de energía y Satélites solares crean un 2 % más de energía.</p><br/><b>+2 % de producción de mineral</b><p>Tus Minas producen un 2 % más.</p><br/><b>+1 al nivel de espionaje</b><p>Se añadirán 1 niveles a tu investigación de espionaje.</p>',
